  WHERE EXISTS (
    SELECT 1 FROM culinary.recipe_ingredient_requirements req
    WHERE  req.recipe_version_id    = v_ver
      AND  req.strictness           = 'required'
      AND  req.preferred_food_form_id IS NULL
