    (recipe_version_id, component_id, requirement_type, preferred_food_form_id,
     quantity, unit, strictness, culinary_role, is_optional, position)
  VALUES
    (v_ver, v_comp, 'exact_form', (SELECT ff.id FROM catalog.food_forms ff
              WHERE ff.status <> 'rejected'
                AND ff.canonical_name_normalized = 'lentille corail seche crue'
              ORDER BY ff.canonical_name_normalized LIMIT 1),
     400, 'g', 'required',
     'proteine vegetale', false, 1);

  INSERT INTO culinary.recipe_ingredient_requirements
