  FROM culinary.recipe_ingredient_requirements req
  WHERE req.recipe_version_id = v_ver
    AND req.position = 9
    AND NOT EXISTS (
      SELECT 1 FROM catalog.food_forms ff
      WHERE ff.status <> 'rejected'
        AND ff.canonical_name_normalized = 'persil frais'
