DO $$
DECLARE v_fam uuid; v_ver uuid; v_comp uuid;
BEGIN
  -- §8.1 Famille de recettes
  INSERT INTO culinary.recipe_families
    (canonical_name, canonical_name_normalized, meal_role, dish_structure, status, confidence_level)
  VALUES
