  SELECT
    'culinary', 'recipe_versions', v_ver, 'content',
    sd.id, 'scraped-v1:IT-008', to_jsonb('fccb0062408f62b36f071464106fc97d'::text),
    'myko_editorial_scraped_v1_recipe',
    run.id, true
  FROM ops.source_datasets sd,
