    3,
    ARRAY['form_not_in_catalog'],
    jsonb_build_object(
      'form',            'Vanille liquide',
      'form_normalized', 'vanille liquide',
      'recipe_family',   'Tarte tatin aux pommes',
      'recipe_code',     'FR-032',
      'position',        5,
      'is_optional',     true,
      'note',            'Forme non résolue dans catalog.food_forms à la date du chargement.'
    ),
    'open'
  FROM culinary.recipe_ingredient_requirements req
  WHERE req.recipe_version_id = v_ver
    AND req.position = 5
    AND NOT EXISTS (
      SELECT 1 FROM catalog.food_forms ff
      WHERE ff.status <> 'rejected'
        AND ff.canonical_name_normalized = 'vanille liquide'
    );

  -- Tâche missing_food_form si la forme « Sel fin » est absente du catalogue
  INSERT INTO quality.review_tasks
